import * as React from 'react';
import { styled } from 'styled-components';

const PageContainer = styled.div`
    width: 100%;
    height: 100%;
    display: grid;
    place-items: center;
`;

const AboutContainer = styled.div`
    height: 100%;
    display: flex;
    flex-direction: column;
    max-width: 1200px;
    padding: 0 4rem;
    background-color: rgb(20, 20, 20, 1);
`;

const Heading = styled.h1`
    margin: 0;
    font-family: 'Rock Salt', cursive;
    font-size: 2.5rem;
`;

const AboutPage = () => {
    return (
        <PageContainer>
            <AboutContainer>
                <Heading>The Journey</Heading>
                <div>
                    <p>
                        An undergraduate, currently in the second year of study for a Masters degree in Software Engineering at Queen's University Belfast, my journey in this
                        industry began over four years ago, and has quickly evolved from a daydream into a lifestyle.
                    </p>
                    <p>
                        What began as a love for video games, tinkering with the Unity engine, making cheap, knock-off side-scrollers, unexpectedly ignited a
                        burning passion for software development and the freedom to create conceivably anything.
                    </p>
                    <p>
                        Resolve, however, is what has propelled me further than anything; recently, I received an award from my university for achieving 'the Best First-Class
                        Performance in Six Modules in MEng Software Engineering at Stage One.' (A little verbose, I know.) What this means however, is that out of almost 400 students,
                        I performed the best. This feat did not come without months of hard work on, and indeed, off campus.
                    </p>
                    <p>
                        In an industry where constant adaptation is necessary to survive, I have thrived through the creation of numerous projects, using a multitude of technologies,
                        including React (which this website uses), .NET for both mobile and desktop, Flutter, and many others, making me well-versed in both front-end and back-end
                        frameworks.
                    </p>
                </div>
                <Heading>My Qualifications</Heading>
                <div>
                    <p>Queen's University Belfast (MEng Software Engineering)</p>
                    <ul>
                        <li>First Year: First-Class (70% and above)</li>
                        <li>(Awarded for the best First-Class performance in the year.)</li>
                    </ul>
                    <p>Dalriada School (A-level)</p>
                    <ul>
                        <li>Digital Technology: A*</li>
                        <li>Mathematics: A</li>
                        <li>History: B</li>
                    </ul>
                    <p>Ballymoney High School (GCSE)</p>
                    <p>9 GCSEs A*-C</p>
                </div>
            </AboutContainer>
        </PageContainer>
    );
};

export default AboutPage;

export const Head = () => <title>Curtis Caulfield &mdash; About</title>;